/*
 * @name GetAssortedEquipments
 * @author Marc Aurel Büttner
 * @param availableAssets (Infotable of HPMC.Core.Asset.Base.DS)
 * @return either availableAssets or the selected assets from the session 'selectedAssets'
 */

const areSessionAssetsPartOfAvailableAssets = (selectedAssets, availAssets, compareCol) => {
  let entryFound = null;
  selectedAssets.rows.toArray().forEach((row, index) => {
    if (entryFound) return;
    entryFound = availAssets.Find({ caption: row.caption });
  });
  return entryFound ? true : false;
};

// check if there are more groups in availableAssets than in the session
const hasLessAssetGroupsInSessionAsAvailable = (selectedAssets, availAssets) => {
  let selectedAssetGroups = [];
  let allAssetGroups = [];

  selectedAssets.rows.toArray().forEach((selectedGroup) => {
    if (selectedAssetGroups.includes(selectedGroup.machineGroup)) return;
    selectedAssetGroups.push(selectedGroup.machineGroup);
  });

  availAssets.rows.toArray().forEach((allAssetGroup) => {
    if (allAssetGroups.includes(allAssetGroup.machineGroup)) return;
    allAssetGroups.push(allAssetGroup.machineGroup);
  });

  return {
    isGroupCountEqual: selectedAssetGroups.length === allAssetGroups.length,
    groupsOfSessionAssets: selectedAssetGroups,
    groupsOfAvailablAssets: allAssetGroups
  };
};

const getSelectedAssetsAndAssetsOfEmptySelectedGroup = (sessionGroups, availableGroups, selectedAssets, availAssets) => {
  const newSelectedAssets = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
    dataShapeName: "HPMC.Core.Asset.Base.DS"
  });

  selectedAssets.rows.toArray().forEach((selectedAsset) => {
    newSelectedAssets.AddRow(selectedAsset);
  });

  sessionGroups.forEach((selectedGroup) => {
    const index = availableGroups.indexOf(selectedGroup);
    if (index > -1) {
      availableGroups.splice(index, 1);
    }
  });

  availAssets.rows
    .toArray()
    .filter((asset) => availableGroups.includes(asset.machineGroup))
    .forEach((notSelectedGroupAsset) => {
      newSelectedAssets.AddRow(notSelectedGroupAsset);
    });

  return newSelectedAssets;
};

const getEquipmentsByPriority = () => {
  //  Due to the dependency of various filters on the session,
  //  a delay of this service is necessary,
  //  as otherwise a difference is always recognized between the MachineGroups of the assets of the session and the MachineGroups of the available assets
  pause(100);

  const currentSessionValues = Resources["CurrentSessionInfo"].GetGlobalSessionValues();

  if (currentSessionValues.selectedAssets && areSessionAssetsPartOfAvailableAssets(currentSessionValues.selectedAssets, availableAssets, "caption")) {
    const { isGroupCountEqual, groupsOfSessionAssets, groupsOfAvailablAssets } = hasLessAssetGroupsInSessionAsAvailable(currentSessionValues.selectedAssets, availableAssets);
    //when no asset-group & asset-type is selected, select all available assets
    if ((!currentSessionValues.selectedMachineGroups || currentSessionValues.selectedMachineGroups.getRowCount() == 0) &&
    (!currentSessionValues.selectedMachineTypes || currentSessionValues.selectedMachineTypes.getRowCount() == 0)) {
      // return currentSessionValues.selectedAssets;
      return availableAssets;
    }

    //when only asset-group is selected, return session-selectedAssets
    if (!currentSessionValues.selectedMachineGroups || currentSessionValues.selectedMachineGroups.getRowCount() == 0) {
      return currentSessionValues.selectedAssets;
    }

    if (!isGroupCountEqual) {
      return getSelectedAssetsAndAssetsOfEmptySelectedGroup(groupsOfSessionAssets, groupsOfAvailablAssets, currentSessionValues.selectedAssets, availableAssets);
    }
    return currentSessionValues.selectedAssets;
  }
  return availableAssets;
};

result = getEquipmentsByPriority();


