/*
 * @name GetDatesDropdown
 * @date 22.12.2020
 * @author Maurizfa CAD-IT
 * @param year		selected year
 * @param month		selected month
 * @return infotable (HPMC.Core.DropdownData.DS) 		list of dates
 * get dates dropdown data
 */
var result;
var loggerBeginning= "["+me.name+":GetDatesDropdown]";

(function(){
    "use strict";

    try { //main try-catch

        // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.DropdownData.DS)
        result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
            infoTableName: "InfoTable",
            dataShapeName: "HPMC.Core.DropdownData.DS"
        });

        let n = parseInt(month);

        let d = new Date();
        d.setFullYear(year,n+1,0); //set to last day of the month

        let newEntry = new Object();// HPMC.Core.DropdownData.DS entry object
        for (var i = 1; i <= d.getDate(); i++) {		
            newEntry.dropdown_id = i; // STRING
            newEntry.dropdown_value = i.toFixed(0); // STRING
            result.AddRow(newEntry);
        }

    } catch(error){
    	logger.error(loggerBeginning + " failed to get date dropdown data  - [ERROR] : "+error);

    } //end of main try-catch
}());


/*
 * @name GetMonthsDropdown
 * @date 22.12.2020
 * @author Maurizfa CAD-IT
 * @return infotable (HPMC.Core.DropdownData.DS) 					list of months
 */
var result;
var loggerBeginning= "["+me.name+":GetMonthsDropdown]";

(function(){
    "use strict";

    try { //main try-catch
        // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.DropdownData.DS)
        result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
            infoTableName: "InfoTable",
            dataShapeName: "HPMC.Core.DropdownData.DS"
        });

        // HPMC.Core.DropdownData.DS entry object
        let newEntry = new Object();
        let d = new Date();
        d.setDate(2);
        for (var i = 0; i < 12; i++) {
            d.setMonth(i);
            newEntry.dropdown_id = i; // STRING
            newEntry.dropdown_value = dateFormat(d,"MMMM"); // STRING
            result.AddRow(newEntry);
        }
    }catch(error){
        logger.error(loggerBeginning + " failed to get month dropdown data - [ERROR] : "+error);
    }
}());


/*
* @name GetNavigationMaxPage
* @date 14.12.2020
* @author Isro Syaeful Iman CAD-IT
* @param dataPerPage(INTEGER) 		total data shown per page on collection
* @param collectionData(infotable)	data on collection
* @return integer 					maximum page
*/
/** type:infotable*/
(function(){
    "use strict";
    let totalData = 1;
    if(collectionData != undefined && collectionData != null) {
    	totalData = collectionData.length;
    }
	let maxPage = Math.ceil(totalData/dataPerPage);
    result = maxPage<1?1:maxPage;
}());


