/*
 * @name GetTimeDropdownValue
 * @date 04.02.2021
 * @author Maurizfa CAD-IT
 * @param currentDate		selected date
 * @return infotable (GetTimeDropdownValue) 		list of time value (year, month, date, week, quarter)
 * 
 */
var result;
var loggerBeginning = "[" + me.name + ":GetTimeDropdownValue]";

(function() {
	"use strict";

	try { //main try-catch

        currentDate.setHours(0,0,0,0); 

		let year = currentDate.getFullYear();
		let month = currentDate.getMonth();
		let date = currentDate.getDate();
		let day = currentDate.getDay();
		day = day > 0 ? day : day + 7;
		let startWeek = dateAddDays(currentDate, -1 * day + 1);
		let endWeek = dateAddDays(currentDate, -1 * day + 7);
		let weeksTable = me.GetWeeksDropdown({
			month: month /* STRING */ ,
			year: year /* STRING */
		});
		let getWeek = Resources["InfoTableFunctions"].Query({
			t: weeksTable /* INFOTABLE */ ,
			query: {
				"filters": {
					"type": "Or",
					"filters": [{
							"type": "EQ",
							"fieldName": "week_start_date",
							"value": startWeek
						},
						{
							"type": "EQ",
							"fieldName": "week_end_date",
							"value": endWeek
						}
					]
				}
			}
		});
		let week = getWeek[0].week_value;
		let quarter = parseInt(month / 3);

		// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Filter.TimeCategory.DS)
		result = DataShapes["HPMC.Core.Filter.TimeCategory.DS"].CreateValues();

		let newEntry = new Object();
		newEntry.year = year.toFixed(0); // STRING
		newEntry.month = month; // STRING
		newEntry.date = date.toFixed(0); // STRING
		newEntry.week = week; // STRING
		newEntry.quarter = quarter; // STRING

        result.AddRow(newEntry);

	} catch (error) {
		logger.error(loggerBeginning + " failed to get time dropdown value  - [ERROR] : " + error);
		result = DataShapes["HPMC.Core.Filter.TimeCategory.DS"].CreateValues();
	} //end of main try-catch
}());


/*
 * @name GetWeeksDropdown
 * @date 23.12.2020
 * @author Maurizfa CAD-IT
 * @param year(STRING) 		e.g. "2020"
 * @param month(STRING) 	e.g. "4"	
 * @return infotable (HPMC.Core.Filter.Weeks.DS) 					list of weeks in a month
 */
var result;

(function() {
	"use strict";
	// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.DropdownData.DS)
	result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
		infoTableName: "InfoTable",
		dataShapeName: "HPMC.Core.Filter.Weeks.DS"
	});

	let m = parseInt(month);
    let y = parseInt(year);

	let d = new Date();
	d.setFullYear(y, m, 1); //set to first day of the month
	let firstday = dateAddDays(d, -1 * d.getDay());
	firstday.setHours(0, 0, 0, 0);

	// HPMC.Core.Filter.Weeks.DS entry object
	let newEntry = new Object();
	let i = 0;
    let start_date, end_date;
    firstday = dateAddDays(firstday, 1);
	while (firstday.getMonth() === m || firstday.getMonth() === m-1 || (firstday.getMonth() === 11 && m === 0)) { //still in the same month
        start_date = dateAddDays(firstday, 0);
        if (firstday.getMonth()!==m){
            start_date.setFullYear(y, m, 1);
        }
        end_date = dateAddDays(firstday, 6);
        if (end_date.getMonth()!==m){
            end_date.setFullYear(y, m+1, 1);
        }

        newEntry.week_value = (i + 1).toFixed(0); // STRING
		newEntry.week_start_date = start_date; // datetime
		newEntry.week_end_date = end_date; // datetime
		result.AddRow(newEntry);
        firstday = dateAddDays(firstday, 7);
        i++;
	}
}());


/*
 * @name GetYearsDropdown
 * @date 22.12.2020
 * @author Maurizfa CAD-IT
 * @return infotable (HPMC.Core.DropdownData.DS) 					list of years
 */
var result;

(function() {
	"use strict";
	// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.DropdownData.DS)
	result = DataShapes["HPMC.Core.DropdownData.DS"].CreateValues();

    let year = new Date().getFullYear();
	let min = year - 2020;
	// HPMC.Core.DropdownData.DS entry object
	let newEntry = new Object();

	for (let i = 0; i <= min; ++i) {
		newEntry.dropdown_id = i; // STRING
		newEntry.dropdown_value = (year-i).toFixed(0); // STRING
		result.AddRow(newEntry);
	}
}());


