/*
 * @name QueryAllAssetsForDropdownData
 * @date 11.12.2020
 * @author Isro Syaeful Iman
 * @param selectedLocation(HPMC.Core.DropdownData.DS) 		selected location id
 * @param selectedMachineType(HPMC.Core.DropdownData.DS)		selected machine type name
 * @param selectedMachineGroup(HPMC.Core.DropdownData.DS)	selected machine group name
 * @return infotable (HPMC.Core.Asset.Base.DS)
 *
 * [COMPLETED] [11/12/2020] 	Return dropdown data for Equipment Number Filter from all Asset
 * 							based on location Id, machine type name and machine group name
 * [REFACTORED] [30/01/2024] Flattened nested service calls.
 * [REFACTORED] [27/02/2024] Adjust inputs
 */

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Asset.Base.DS)
let result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
  dataShapeName: "HPMC.Core.Asset.Base.DS",
});

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(RootEntityList)
const assets = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
  dataShapeName: "EntityList",
});
// Nasty loop incoming... but it basically looks into the "assetGroups" property and filters the assets. That's what you get for not using "Networks"
selectedLocations.rows.toArray().forEach((row) => {
  const { assetGroups: assetGroupTable } = row;
  assetGroupTable.rows
    .toArray()
    .filter((assetGroup) => {
      if (!selectedMachineGroup || selectedMachineGroup.getRowCount() === 0) return assetGroup;
      return (
        selectedMachineGroup.getRowCount() === 0 ||
        selectedMachineGroup.Find({ value: assetGroup.groupId })
      );
    })
    .forEach((assetGroup) => {
      const { assets: assetList } = assetGroup;
      assetList.rows
        .toArray()
        .filter((asset) => {
          if (!selectedMachineType || selectedMachineType.getRowCount() === 0) return asset;
            try {
              const doesAssetThingExist = Things[asset.assetThingname].machineType;
            } catch (err) {
              logger.error(me.name + ".QueryAllAssetsFiltered Not found configured asset [" + asset.assetThingname + "] on " + selectedLocations.name + " (" + selectedLocations.companyName +")");
              return;
            }
          return (
            selectedMachineType.Find({ value: Things[asset.assetThingname].machineType })
          );
        })
        .forEach((asset) => assets.AddRow({ name: asset.assetThingname }));
    });
});

assets.rows.toArray().forEach((row) => {
  const assetThing = Things[row.name];
  if (assetThing && assetThing.isConnected) {
    result.AddRow({
      description: assetThing.description, // STRING
      thingTemplate: assetThing.thingTemplate, // THINGTEMPLATENAME
      tags: assetThing.tags, // TAGS
      name: assetThing.name, // STRING
      diameter: assetThing.diameter, // NUMBER
      assetImage: undefined, // IMAGE
      caption: assetThing.caption, // STRING
      maxMeterPerMinute: assetThing.maxMeterPerMinute, // NUMBER
      databaseId: assetThing.databaseId, // STRING [Primary Key]
      maxPowerConsumption: assetThing.maxPowerConsumption, // NUMBER
      machineType: assetThing.machineType, // STRING
      maxRPM: assetThing.maxRPM, // NUMBER
      sawType: assetThing.sawType, // STRING
      machineSubType: assetThing.machineSubType, // STRING
      manufacturer: assetThing.manufacturer, // STRING
      manufacturingYear: assetThing.manufacturingYear, // NUMBER
      sapId: assetThing.sapId, // STRING
      serialNumber: assetThing.serialNumber, // STRING
      machineId: assetThing.machineId, // STRING
      locId: assetThing.locId, // STRING
      ucId: assetThing.ucId, // STRING
      relatedDowntimeReasons: assetThing.relatedDowntimeReasons, // STRING
      machineName: assetThing.machineName, // STRING
      equipmentNumber: assetThing.equipmentNumber, // STRING
      machineGroup: assetThing.machineGroup, // STRING
      plcController: assetThing.plcController, // STRING
      commInterface: assetThing.commInterface, // STRING
      commProtocol: assetThing.commProtocol, // STRING
      isConnected: assetThing.isConnected, // BOOLEAN
      installationDate: assetThing.installationDate, // DATETIME
    });
  } 
});

result.Sort({ name: "caption" });


/*
 * @name QueryAllAssetsForDropdownData
 * @date 11.12.2020
 * @author Isro Syaeful Iman
 * @param selectedLocation(HPMC.Core.DropdownData.DS) 		selected location id
 * @param selectedMachineType(HPMC.Core.DropdownData.DS)		selected machine type name
 * @param selectedMachineGroup(HPMC.Core.DropdownData.DS)	selected machine group name
 * @param selectedCompany(HPMC.Core.Country.DS) 				selected unique company id
 * @return infotable (HPMC.Core.Asset.Base.DS)
 *
 * [COMPLETED] [11/12/2020] 	Return dropdown data for Equipment Number Filter from all Asset
 * 							based on location Id, machine type name and machine group name
 * [REFACTORED] [30/01/2024] Flattened nested service calls.
 */

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Asset.Base.DS)
let result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "HPMC.Core.Asset.Base.DS" });

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(EntityList)
const propertyNames = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "EntityList" });
propertyNames.AddRow({ name: "ucId" });
propertyNames.AddRow({ name: "locId" });
propertyNames.AddRow({ name: "assetGroups" });
// propertyNames.AddRow({ name: "machineGroup" });
// propertyNames.AddRow({ name: "machineType" });

const locIdArr = [];
selectedLocation.rows.toArray().forEach((row) => locIdArr.push(row.dropdown_id));

const ucIdArr = [];
selectedCompany.rows.toArray().forEach((row) => ucIdArr.push(row.company_id));

const query = {
    // sorts: [{ fieldName: "equipmentNumber", isAscending: true }],
    filters: {
        type: "And",
        filters: [
            { type: "IN", fieldName: "locId", values: locIdArr },
            { type: "IN", fieldName: "ucId", values: ucIdArr }
        ]
    }
};

// result: INFOTABLE dataShape: "RootEntityList"
const locations = ThingTemplates["HPMC.Core.Location.TT"].QueryImplementingThingsOptimized({
    networkName: undefined /* STRING */,
    networkParentNode: undefined /* STRING */,
    networkMaxDepth: undefined /* INTEGER {"defaultValue":0} */,
    maxItems: 200 /* NUMBER {"defaultValue":500} */,
    basicPropertyNames: undefined /* INFOTABLE {"dataShape":"EntityList"} */,
    withPermissions: false /* BOOLEAN {"defaultValue":false} */,
    offset: 0 /* NUMBER {"defaultValue":0} */,
    nameMask: undefined /* STRING */,
    propertyNames: propertyNames /* INFOTABLE {"dataShape":"EntityList"} */,
    query: query /* QUERY */,
    tags: undefined /* TAGS */
});

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(RootEntityList)
const assets = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "EntityList" });
// Nasty loop incoming... but it basically looks into the "assetGroups" property and filters the assets. That's what you get for not using "Networks"
locations.rows.toArray().forEach((row) => {
    const assetGroupTable = row.assetGroups;
    assetGroupTable.rows
        .toArray()
        .filter((assetGroup) => selectedMachineGroup.getRowCount() === 0 || selectedMachineGroup.Find({ dropdown_id: assetGroup.groupId }))
        .forEach((assetGroup) => {
            const assetList = assetGroup.assets;
            assetList.rows
                .toArray()
                .filter((asset) => selectedMachineGroup.getRowCount() === 0 || selectedMachineType.Find({ dropdown_id: Things[asset.assetThingname].machineType }))
                .forEach((asset) => assets.AddRow({ name: asset.assetThingname }));
        });
});

