/**
 * @name QueryAllCountriesBasedOnLocationEntities
 * @date 29.01.2024
 * @author Dan Zielinsky
 * @return infotable HPMC.Core.Country.DS
 *
 * [COMPLETED] [29/01/2024] Replaced "QueryAllCountriesByUserLocationPermission" service
 */

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Company.DS)
const result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "HPMC.Core.Company.DS" });

const getCountryIdArr = () => {
    const locationEntities = ThingTemplates["HPMC.Core.Location.TT"].GetImplementingThingsWithData();

    const companyIdQueryParam = [];
    locationEntities.rows
        .toArray()
        .filter((row) => row.ucId)
        .forEach((row) => {
            companyIdQueryParam.push({
                type: "EQ",
                fieldName: "company_id",
                value: row.ucId
            });
        });
    return companyIdQueryParam;
};

const companies = Things["HPMC.Core.Company.DT"].QueryDataTableEntries({
    maxItems: 200 /* NUMBER {"defaultValue":500} */,
    query: {
        filters: {
            type: "And",
            filters: [
                {
                    type: "EQ",
                    fieldName: "country_id",
                    value: selectedCountry.country_id
                },
                {
                    type: "OR",
                    filters: getCountryIdArr()
                }
            ]
        }
    }
});

companies.rows.toArray().forEach((row) => result.AddRow(row));

result.Sort({ name: "company_name" });


/**
 * @name QueryAllCompaniesForDropdownData
 * @date 11.12.2020
 * @author Isro Syaeful Iman
 * @param selectedCountry(HPMC.Core.Country.DS)
 * @return infotable(HPMC.Core.Company.DS)
 *
 * [COMPLETED] [11/12/2020] Get data for Company Dropdown Data
 * [COMPLETED] [08/02/2021] add sub region filter
 * [COMPLETED] [15/02/2021] filter based on location thing permission
 * [REFACTED] [29/01/2024] Uses location entity visibility permissions to return companies
 */

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Company.DS)
const result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "HPMC.Core.Company.DS" });

const getCountryIdArr = () => {
    const countryIdArr = [];
    if (selectedCountry.getRowCount() > 0) {
        selectedCountry.rows.toArray().forEach((row) => countryIdArr.push(row.country_id));
        return countryIdArr;
    }
    // If no country is selected, all companies (based on location entities) are returned

    // result: INFOTABLE dataShape: "RootEntityList"
    const locationEntities = ThingTemplates["HPMC.Core.Location.TT"].GetImplementingThings();
    const companyIdArr = [];

    locationEntities.rows.toArray().forEach((row) => {
        const companyId = Things[row.name].ucId;
        if (companyId && companyIdArr.includes(companyId) === false) companyIdArr.push(companyId);
    });

    // result: INFOTABLE dataShape: ""
    // Warning: Potential Performance issue, since query filter is performed in Memory
    const companies = Things["HPMC.Core.Company.DT"].QueryDataTableEntries({
        maxItems: 200 /* NUMBER {"defaultValue":500} */,
        query: {
            filters: { type: "IN", fieldName: "company_id", values: companyIdArr }
        } /* QUERY */
    });

    companies.rows.toArray().forEach((row) => {
        const countryId = row.country_id;
        if (countryIdArr.includes(countryId) === false) countryIdArr.push(countryId);
    });
    return countryIdArr;
};

const companies = Things["HPMC.Core.Company.DT"].QueryDataTableEntries({
    maxItems: 200 /* NUMBER {"defaultValue":500} */,
    query: {
        filters: { type: "IN", fieldName: "country_id", values: getCountryIdArr() }
    } /* QUERY */
});

companies.rows.toArray().forEach((row) => result.AddRow(row));


