/**
 * @name QueryAllCountriesForDropdownData
 * @date 11.12.2020
 * @author Isro Syaeful Iman
 * @return infotable HPMC.Core.DropdownData.DS
 *
 * [COMPLETED] [11/12/2020] Get all countries for Dropdown Data
 * [COMPLETED] [08/01/2021] add sub region filter
 * [COMPLETED] [15/01/2021] filter based on location thing permission
 * [REFACTORED] [29/01/2024] removed depency from nested service; visibility based on users organization permissions
 */

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.DropdownData.DS)
const result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
    dataShapeName: "HPMC.Core.DropdownData.DS"
});

// result: INFOTABLE dataShape: "RootEntityList"
const locationEntities = ThingTemplates["HPMC.Core.Location.TT"].GetImplementingThingsWithData();

const getCountryId = (countryName) => {
    const findValues = Things["HPMC.Core.Country.DT"].CreateValuesWithData({ values: { country_name: countryName } /* JSON */ });
    return Things["HPMC.Core.Country.DT"].FindDataTableEntries({ values: findValues /* INFOTABLE */ }).country_id;
};

locationEntities.rows.toArray().forEach((row) => {
    if (!row.country) return;
    const isDuplicate = (searchCountry) => result.rows.toArray().find((row) => row.country_name === searchCountry);
    if (!!isDuplicate(row.country)) return;

    const countryId = getCountryId(row.country);
    if (!countryId) return;

    result.AddRow({
        dropdown_id: countryId, // STRING [Primary Key]
        dropdown_value: row.country // STRING
    });
});


