/*
 * @name QueryAllMachineGroupForDropdownData
 * @date 11.12.2020
 * @author Isro Syaeful Iman
 * @param selectedLocation(HPMC.Core.DropdownData.DS) 	Selected Location ID
 * @param selectedMachineType(HPMC.Core.DropdownData.DS) 	Selected Machine Type Name
 * @param selectedCompanyId(STRING) 					Selected unique company ID
 * @return infotable (HPMC.Core.DropdownData.DS)
 *
 * [COMPLETED] [11/12/2020] 	Return dropdown data for Machine Group Filter from all Asset
 * 							based on location Id and machine type
 * [REFACTORED] [29/01/2024] Flattened nested service calls.
 */

const createMachineGroupResultSet = (assetGroupTable) => {
    const groupName = assetGroupTable.groupCaption; // STRING
    const groupId = assetGroupTable.groupId; // STRING
    const assetList = assetGroupTable.assets; // INFOTABLE dataShape: "HPMC.Core.Asset.MetaData.DS"
    assetList.rows.toArray().forEach((asset) => {
        const assetType = Things[asset.assetThingname].assetType;
        // Check if machineGroup is already in result set
        const findEntry = result.Find({ dropdown_id: groupId });
        if (findEntry) return;
        // Check if "selectedMachineType" param has entries, because it adds additional filtering
        if (selectedMachineType.getRowCount() > 0 && selectedMachineType.dropdown_id !== assetType) return;
        result.AddRow({
            value: groupId, // STRING [Primary Key]
            displayValue: groupName // STRING
        });
    });
};

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.DropdownData.DS)
let result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "HPMC.Core.DropdownData.DS" });

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(EntityList)
const propertyNames = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "EntityList" });
propertyNames.AddRow({ name: "locId" });
propertyNames.AddRow({ name: "assetGroups" });

const locIdArr = [];
selectedLocation.rows.toArray().forEach((row) => locIdArr.push(row.dropdown_id));
const query = { filters: { type: "IN", fieldName: "locId", values: locIdArr } };

// result: INFOTABLE dataShape: "RootEntityList"
const locations = ThingTemplates["HPMC.Core.Location.TT"].QueryImplementingThingsOptimized({
    networkName: undefined /* STRING */,
    networkParentNode: undefined /* STRING */,
    networkMaxDepth: undefined /* INTEGER {"defaultValue":0} */,
    maxItems: 200 /* NUMBER {"defaultValue":500} */,
    basicPropertyNames: undefined /* INFOTABLE {"dataShape":"EntityList"} */,
    withPermissions: false /* BOOLEAN {"defaultValue":false} */,
    offset: 0 /* NUMBER {"defaultValue":0} */,
    nameMask: undefined /* STRING */,
    propertyNames: propertyNames /* INFOTABLE {"dataShape":"EntityList"} */,
    query: query /* QUERY */,
    tags: undefined /* TAGS */
});

const machineTypeArr = [];
selectedMachineType.rows.toArray().forEach((row) => machineTypeArr.push(row.dropdown_id));

locations.rows.toArray().forEach((location) => {
    const assetGroups = location.assetGroups; // INFOTABLE dataShape: "HPMC.Core.Asset.Group.DS"
    if (!assetGroups) return;
    assetGroups.rows.toArray().forEach((group) => createMachineGroupResultSet(group));
});


/*
 * @name QueryAllMachineGroupForDropdownData
 * @date 11.12.2020
 * @author Isro Syaeful Iman
 * @param selectedLocations(HPMC.Core.Location.DS) 	Selected Location ID
 * @param selectedMachineTypes(HPMC.Core.Dropdown.DS) 	Selected Machine Type Name
 * @param selectedCompanyId(STRING) 					Selected unique company ID
 * @return infotable (HPMC.Core.Dropdown.DS)
 *
 * [COMPLETED] [11/12/2020] 	Return dropdown data for Machine Group Filter from all Asset
 * 							based on location Id and machine type
 * [REFACTORED] [29/01/2024] Flattened nested service calls.
 * [REFACTORED] [27/02/2024] Updated Inputs
 */
const loggerBeginning = "["+me.name+":QueryAllMachineGroups]";

const createMachineGroupResultSet = (assetGroupTable) => {
    const { groupCaption: groupName, groupId, assets: assetList } = assetGroupTable;
    if (!assetList || assetList.getRowCount() == 0) {
        result.AddRow({
            value: groupId, // STRING [Primary Key]
            displayValue: groupName // STRING
        });
        return;
    }


    assetList.rows.toArray().forEach((asset) => {
        logger.info(loggerBeginning + asset.assetThingname);
        const assetEntity = Things[asset.assetThingname];
        try {
            const doesAssetThingExist = Things[asset.assetThingname].assetType;
        } catch (err) {
            logger.error(me.name + ".QueryAllMachineGroups Not found configured asset [" + asset.assetThingname + "] on " + selectedLocations.name + " (" + selectedLocations.companyName +")");
        }
        // Check if machineGroup is already in result set
        const findEntry = result.Find({ value: groupId });
        if (findEntry) return;
        // Check if "selectedMachineType" param has entries, because it adds additional filtering
        //   if (selectedMachineTypes && selectedMachineTypes.getRowCount() > 0 && !selectedMachineTypes.Find({value: assetEntity.assetType})) Original code 
        if (selectedMachineTypes && selectedMachineTypes.getRowCount() > 0){
        	logger.info(loggerBeginning+" Line 42 selectedMachineTypes and selectedMachineTypew.getRowCount > 0");

        }
        if(!selectedMachineTypes.Find({value: assetEntity.assetType})){
        	logger.info(loggerBeginning+" Line 46 assetEntity.assetType not found in selectedMachineTypes:"+ assetEntity.assetType);
        	return;
        }	

        result.AddRow({
            value: groupId, // STRING [Primary Key]
            displayValue: groupName // STRING
        });
    });

};

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Dropdown.DS)
let result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "HPMC.Core.Dropdown.DS" });

selectedLocations.rows.toArray().forEach((location) => {
    const assetGroups = location.assetGroups; // INFOTABLE dataShape: "HPMC.Core.Asset.Group.DS"
    if (!assetGroups) return;
    assetGroups.rows.toArray().forEach((group) => createMachineGroupResultSet(group));
});

result.Sort({ name: "displayValue" });


