/*
* @name 	QueryAllMachineTypeOfLocation
* @date 	11.12.2020
* @author 	Isro Syaeful Iman
* @param 	selectedLocation(HPMC.Core.DropdownData.DS)	selected location ID
* @param 	selectedCompanyId(STRING)				selected unique company ID	
* @return 	infotable (HPMC.Core.DropdownData.DS)
*
* [COMPLETED] [11/12/2020] 	Return dropdown data for Machine Type Filter from all Asset 
* 							based on selected location and unique company Id
* [EDIT] Copy of QueryAllMachineTypeForDropdownData because disconnected assets are not shown in dropdown
*/


// result: INFOTABLE dataShape: "HPMC.Core.DropdownData.DS"
var result;
var loggerBeginning= "["+me.name+":QueryAllMachineTypeForDropdownData]";

(function(){
    "use strict";

    try {
        // logger.info(loggerBeginning+ " start to query all machine type for dropdown data");
        let tempData  = me.getAllMachineTypeDropdownData({
            		companyId:selectedCompanyId,
                    locationId: selectedLocation[0].dropdown_id /* STRING */
                });

        result = DataShapes["HPMC.Core.DropdownData.DS"].CreateValues();
        result.AddRow({dropdown_value:""});
        for (let i =0;i<tempData.length;i++){
            result.AddRow({dropdown_id:tempData[i].dropdown_value,
                           dropdown_value:tempData[i].dropdown_value});
        }
        for (let i =0;i<result.length;i++){
            let data = result.rows[i];
            if (data.dropdown_value!==""){
                //get language from user config
                let currentLanguage = Resources['CurrentSessionInfo'].GetCurrentUserLanguage();
                // get token value from language
                let token = Resources['RuntimeLocalizationFunctions'].GetEffectiveTokenForLanguage({
                    language: currentLanguage /* STRING */ ,
                    token: "HPMC.MachineType." + data.dropdown_value.split(" ").join("") /* STRING */ ,
                });
                data.dropdown_value = token ;//+ data.dropdown_value;
            }
        }
    }
    catch(error){
        logger.error(loggerBeginning+ " failed to query all machine type for dropdown data - [ERROR] [" + error.lineNumber + "]: " +error);

        result = DataShapes["HPMC.Core.DropdownData.DS"].CreateValues();
        result.AddRow({dropdown_value:""});
    }
}());


/*
 * @name 	GetMachineTypeDropdownData
 * @date 	11.12.2020
 * @author 	Isro Syaeful Iman
 * @param 	selectedLocations(HPMC.Core.Location.DS)	selected location ID
 * @param 	selectedCompanyId(STRING)				selected unique company ID
 * @return 	infotable (HPMC.Core.Dropdown.DS)
 *
 * [COMPLETED] [11/12/2020] Return dropdown data for Machine Type Filter from all Asset
 * 							based on selected location and unique company Id
 * [REFACTORED] [29/01/2024] Flattened nested service calls.
 * [REFACTORED] [27/02/2024] Updated Inputs
 */

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.Core.Dropdown.DS)
let result = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "HPMC.Core.Dropdown.DS" });

// CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(EntityList)
const propertyNames = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({ dataShapeName: "EntityList" });
propertyNames.AddRow({ name: "locId" });
// propertyNames.AddRow({ name: "machineType" });

const locIdArr = selectedLocations.rows.toArray().map((row) => row.locId);

const query = { filters: { type: "IN", fieldName: "locId", values: locIdArr } };

// result: INFOTABLE dataShape: "RootEntityList"
const assetsOfLocation = ThingTemplates["HPMC.Core.Asset.TT"].QueryImplementingThingsWithNamedData({
    networkName: undefined /* STRING */,
    networkParentNode: undefined /* STRING */,
    networkMaxDepth: undefined /* INTEGER {"defaultValue":0} */,
    maxItems: 1000 /* NUMBER {"defaultValue":500} */,
    basicPropertyNames: undefined /* INFOTABLE {"dataShape":"EntityList"} */,
    withPermissions: false /* BOOLEAN {"defaultValue":false} */,
    offset: 0 /* NUMBER {"defaultValue":0} */,
    nameMask: undefined /* STRING */,
    propertyNames: propertyNames /* INFOTABLE {"dataShape":"EntityList"} */,
    query: query /* QUERY */,
    tags: undefined /* TAGS */
});

const machineTypeArr = [];
assetsOfLocation.rows.toArray().forEach((row) => {
  const machineTypeOfSelected = Things[row.name].machineType;
    if(!machineTypeOfSelected){
    logger.warn(me.name+" QueryAllMachineTypes line 46 "+row.name);
    }

  if (machineTypeArr.includes(machineTypeOfSelected) === true) return;
  machineTypeArr.push(machineTypeOfSelected);
  result.AddRow({
    value: machineTypeOfSelected, // STRING [Primary Key]
    displayValue: machineTypeOfSelected, // STRING
  });
});

result.Sort({ name: "displayValue" });


/**
 * @name SetCurrentPageNavigationBarData
 * @date 01.02.2021
 * @author Isro Syaeful Iman
 * @param currentPage(STRING)  	current page open
 * @return infotable (HPMC.Core.Container.NavigationBar.DS)		
 *
 * Set current page opened as current page at Navigation Bar Data on session 
 */
var result;
var loggerBeginning = "[" + me.name+":SetCurrentPageNavigationBarData]";
(function(){
    "use strict";
    try{

        Resources["CurrentSessionInfo"].SetGlobalSessionStringValue({
            name: "currentPage" /* STRING */,
            value: currentPage /* STRING */
        });

        result = Resources["CurrentSessionInfo"].GetGlobalSessionValues();
    }catch(error){
        logger.error(loggerBeginning + " failed to set global session for navigation bar in master header.");
    }
}());


const hasDifference = (selectedValues, sessionValues, compareCol) => {
  if (selectedValues.getRowCount() !== sessionValues.getRowCount()) {
    return true;
  }

  let hasDifferenceInRow = false;
  selectedValues.rows.toArray().forEach((row, index) => {
    if (hasDifferenceInRow) {
      return;
    }
    hasDifferenceInRow = row[compareCol] !== sessionValues[index][compareCol];
  });
  return hasDifferenceInRow;
};

const currentSessionInfo = Resources["CurrentSessionInfo"].GetGlobalSessionValues();

if (currentSessionInfo.getRowCount() > 0 && !currentSessionInfo.screenRotationEnabled) {
  const {
    selectedCountries: sessionCountries,
    selectedCompanies: sessionCompanies,
    selectedLocations: sessionLocations,
    selectedMachineTypes: sessionMachineTypes,
    selectedMachineGroups: sessionMachineGroups,
    selectedAssets: sessionAssets,
  } = currentSessionInfo[0];

  if (
    selectedCountries &&
    selectedCountries.getRowCount() > 0 &&
    hasDifference(selectedCountries, sessionCountries, "country_id")
  ) {
    Resources["CurrentSessionInfo"].SetGlobalSessionStringValue({
      name: "selectedCountries" /* STRING */,
      value: selectedCountries /* STRING */,
    });
  }

  if (selectedCompanies && hasDifference(selectedCompanies, sessionCompanies, "company_id")) {
    Resources["CurrentSessionInfo"].SetGlobalSessionStringValue({
      name: "selectedCompanies" /* STRING */,
      value: selectedCompanies /* STRING */,
    });
  }

  if (selectedLocations && hasDifference(selectedLocations, sessionLocations, "companyName")) {
    Resources["CurrentSessionInfo"].SetGlobalSessionStringValue({
      name: "selectedLocations" /* STRING */,
      value: selectedLocations /* STRING */,
    });
  }

  if (selectedMachineTypes && hasDifference(selectedMachineTypes, sessionMachineTypes, "value")) {
    Resources["CurrentSessionInfo"].SetGlobalSessionStringValue({
      name: "selectedMachineTypes" /* STRING */,
      value: selectedMachineTypes /* STRING */,
    });
  }

  if (
    selectedMachineGroups &&
    hasDifference(selectedMachineGroups, sessionMachineGroups, "value")
  ) {
    Resources["CurrentSessionInfo"].SetGlobalSessionStringValue({
      name: "selectedMachineGroups" /* STRING */,
      value: selectedMachineGroups /* STRING */,
    });
  }

  if (
    selectedAssets &&
    selectedAssets.getRowCount() > 0 &&
    hasDifference(selectedAssets, sessionAssets, "caption")
  ) {
    Resources["CurrentSessionInfo"].SetGlobalSessionInfoTableValue({
      name: "selectedAssets" /* STRING */,
      value: selectedAssets /* INFOTABLE */, //map assets. databaseId
    });
  }

  if ( is24hView && is24hView == "true" || is24hView == "false") {
    try {
      Resources["CurrentSessionInfo"].SetGlobalSessionBooleanValue({
        name: "is24hView" /* STRING */,
        value: is24hView /* BOOLEAN */
      });
    } catch(err) {
      logger.warn(me.name + ".SetFilterSessionVariables: Tried to set session variable 'is24hView', but module is not available.");
    }
  }

  if ((isGroupView && isGroupView == "true") || isGroupView == "false") {
    try {
      Resources["CurrentSessionInfo"].SetGlobalSessionBooleanValue({
        name: "isGroupView" /* STRING */,
        value: isGroupView /* BOOLEAN */
      });
    } catch (err) {
      logger.warn(me.name + ".SetFilterSessionVariables: Tried to set session variable 'isGroupView', but module is not available.");
    }
  }

}


